import NullBtn from "../Buttons/NullBtn";
import PurpleBtn from "../Buttons/PurpleBtn";

import searchIcon from "../../Files/Search.png"
import cartIcon from "../../Files/Shopping cart.png"

function Header() {
  return (
    <header className="header">
      <div className="logo"></div>
      <div className="search-bar">
        <img src={searchIcon} alt="search" className="search-icon" />
        <input type="text" placeholder="Поиск" className="search-input" />
      </div>
      <div className="actions">
        <button className="shopping-cart-btn">
          <img src={cartIcon} alt="shopping-cart" className="shopping-cart-icon" />
        </button>
        <NullBtn Text={"Войти"}/>
        <PurpleBtn Text={"Регистрация"}/>
      </div>
    </header>
  );
}

export default Header;
